import { Product } from "model/productModel";

export const fetchProducts = async (category?: string, subcategory?: string): Promise<Product[]> => {
    try {
        let endpoint = "http://localhost:5001/api/products"; // ✅ Default: All products
        if (category) {
            endpoint = `http://localhost:5001/api/products/category/${encodeURIComponent(category)}`;
            if (subcategory) {
                endpoint += `/${encodeURIComponent(subcategory)}`;
            }
        }
        console.log(`📡 Fetching products from: ${endpoint}`); // ✅ Debugging Log

        const response = await fetch(endpoint);
        if (!response.ok) throw new Error(`Server responded with ${response.status}`);

        return await response.json();
    } catch (error) {
        console.error("❌ Failed to fetch products:", error);
        return [];
    }
};

export const fetchProductByName = async (name: string): Promise<Product> => {
    const response = await fetch(`http://localhost:5001/api/products/details/${encodeURIComponent(name)}`);

    if (!response.ok) {
        throw new Error("Failed to fetch product details");
    }

    return response.json();
};

export const fetchBestDeals = async () => {
    const response = await fetch('http://localhost:5001/api/products/best-deals');
    if (!response.ok) {
        throw new Error('Failed to fetch best deals');
    }
    return await response.json();
};

export const fetchTopSellers = async () => {
    const response = await fetch('http://localhost:5001/api/products/top-sellers');
    if (!response.ok) {
        throw new Error('Failed to fetch top sellers');
    }
    return await response.json();
};

export const fetchNewAdded = async () => {
    const response = await fetch('http://localhost:5001/api/products/new-added');
    if (!response.ok) {
        throw new Error('Failed to fetch newly added');
    }
    return await response.json();
};

export const getCategorySpecifications = async (category: string, subcategory?: string) => {
    const params = new URLSearchParams();
    params.append("category", category);
    if (subcategory) params.append("subcategory", subcategory);

    const res = await fetch(`/api/products/specifications?${params.toString()}`);
    if (!res.ok) throw new Error("Failed to fetch specifications");

    return await res.json(); // returns { Brand: [...], Size: [...], etc. }
};

export const filterProducts = async (
    category: string,
    subcategory: string | undefined,
    filters: Record<string, string[]>
) => {
    const res = await fetch(`/api/products/filter`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ category, subcategory, filters }),
    });

    if (!res.ok) throw new Error("Failed to fetch filtered products");

    return await res.json(); // returns products[]
};
